    private static class SafeDnsResolver implements DnsResolver {

        @Override
        public InetAddress[] resolve(String host) throws UnknownHostException {
            if (host == null || host.trim().isEmpty()) {
                throw new UnknownHostException("Empty host");
            }
            String asciiHost = IDN.toASCII(host.trim());
            String lower = asciiHost.toLowerCase();
            if ("localhost".equals(lower)) {
                throw new UnknownHostException("Unsafe host: localhost");
            }

            InetAddress[] addresses = InetAddress.getAllByName(asciiHost);
            if (addresses == null || addresses.length == 0) {
                throw new UnknownHostException("No addresses for host: " + asciiHost);
            }

            for (InetAddress addr : addresses) {
                if (!isPublicAddress(addr)) {
                    throw new UnknownHostException("Unsafe address resolved for host " + asciiHost + ": " + addr.getHostAddress());
