     * 重定向策略：仅允许到 http/https，且目标主机解析结果必须安全
     */
    private static class SafeRedirectStrategy extends DefaultRedirectStrategy {
        private final SafeDnsResolver dnsResolver;

        SafeRedirectStrategy(SafeDnsResolver dnsResolver) {
            this.dnsResolver = dnsResolver;
        }

        @Override
        public HttpUriRequest getRedirect(HttpRequest request, HttpResponse response, HttpContext context) throws ProtocolException {
            HttpUriRequest redirect = super.getRedirect(request, response, context);
            URI uri = redirect.getURI();

            if (!isAllowedScheme(uri.getScheme())) {
                throw new ProtocolException("Unsafe redirect scheme: " + uri.getScheme());
            }
            if (uri.getUserInfo() != null) {
                throw new ProtocolException("Unsafe redirect with user-info");
            }
            if (uri.getHost() == null) {
                throw new ProtocolException("Unsafe redirect: missing host");
            }
            if (uri.getPort() != -1 && (uri.getPort() < 1 || uri.getPort() > 65535)) {
                throw new ProtocolException("Unsafe redirect: invalid port");
            }

            // 使用相同的安全DNS解析逻辑验证目标主机
            try {
                dnsResolver.resolve(uri.getHost());
            } catch (UnknownHostException e) {
                throw new ProtocolException("Unsafe redirect target: " + e.getMessage());
            }

            return redirect;
        }
    }

    /**
     * 判断地址是否为可公开访问地址（非内网/本地/保留）
     */
    private static boolean isPublicAddress(InetAddress addr) {
        if (addr.isAnyLocalAddress()) return false;      // 0.0.0.0 / ::
        if (addr.isLoopbackAddress()) return false;      // 127.0.0.0/8, ::1
        if (addr.isLinkLocalAddress()) return false;     // 169.254.0.0/16, fe80::/10
        if (addr.isSiteLocalAddress()) return false;     // 10/8, 172.16/12, 192.168/16
        if (addr.isMulticastAddress()) return false;     // 224/4, ff00::/8

        if (addr instanceof Inet4Address) {
            byte[] b = addr.getAddress();
            int b0 = b[0] & 0xFF;
            int b1 = b[1] & 0xFF;

            // 100.64.0.0/10 (Carrier-grade NAT)
            if (b0 == 100 && (b1 >= 64 && b1 <= 127)) return false;

            // 198.18.0.0/15 (benchmarking)
            if (b0 == 198 && (b1 == 18 || b1 == 19)) return false;

            // 0.0.0.0/8
            if (b0 == 0) return false;

            // 240.0.0.0/4 reserved
            if (b0 >= 240) return false;

            // 192.0.0.0/24 (IETF Protocol Assignments, conservative block)
            if (b0 == 192 && b1 == 0) return false;

            // 192.0.2.0/24, 198.51.100.0/24, 203.0.113.0/24 (TEST-NET ranges)
            if ((b0 == 192 && b1 == 0 && (b[2] & 0xFF) == 2) ||
                (b0 == 198 && b1 == 51 && (b[2] & 0xFF) == 100) ||
                (b0 == 203 && b1 == 0 && (b[2] & 0xFF) == 113)) {
                return false;
            }
        } else if (addr instanceof Inet6Address) {
            byte[] b = addr.getAddress();
            int b0 = b[0] & 0xFF;

            // Unique Local Address fc00::/7
            if ((b0 & 0xFE) == 0xFC) { // 0b11111100 => 0xFC or 0xFD
                return false;
            }

            // Deprecated site-local fec0::/10 (just in case)
            if (b0 == 0xFE) {
                int b1 = b[1] & 0xC0;
                // fe80::/10 is link-local (already caught), feC0::/10 site-local
                if (b1 == 0xC0) {
                    return false;
                }
            }

            // 2001:db8::/32 documentation range
            if ((b0 == 0x20) && ((b[1] & 0xFF) == 0x01) && ((b[2] & 0xFF) == 0x0D) && ((b[3] & 0xFF) == 0xB8)) {
                return false;
            }
        }

        return true;
    }
}

