     * @return the response body as a String (UTF-8 if charset is not specified by the server)
     * @throws IllegalArgumentException if the URL is null/blank, invalid, or uses an unsupported scheme
     * @throws IOException if an I/O error occurs
     * @throws HttpResponseException if the server returns a non-2xx status code
     */
    public String fetchUrlContent(String userUrl) throws IOException {
        if (userUrl == null || userUrl.trim().isEmpty()) {
            throw new IllegalArgumentException("URL must not be null or blank.");
        }

        final URI uri = toHttpOrHttpsUri(userUrl.trim());

        RequestConfig requestConfig = RequestConfig.custom()
                .setConnectTimeout(DEFAULT_CONNECT_TIMEOUT_MS)
                .setSocketTimeout(DEFAULT_SOCKET_TIMEOUT_MS)
                .setConnectionRequestTimeout(DEFAULT_CONNECTION_REQUEST_TIMEOUT_MS)
                .setRedirectsEnabled(true)
                .setCircularRedirectsAllowed(false)
                .setCookieSpec(CookieSpecs.STANDARD)
                .build();

        try (CloseableHttpClient httpClient = HttpClients.custom()
                .setDefaultRequestConfig(requestConfig)
                .disableAuthCaching()
                .disableCookieManagement()
                .build()) {

            HttpGet httpGet = new HttpGet(uri);
            httpGet.setHeader(HttpHeaders.USER_AGENT, DEFAULT_USER_AGENT);
            httpGet.setHeader(HttpHeaders.ACCEPT, "text/html,application/json;q=0.9,*/*;q=0.8");
            httpGet.setHeader(HttpHeaders.ACCEPT_CHARSET, "utf-8");
            httpGet.setHeader(HttpHeaders.ACCEPT_ENCODING, "gzip");

            try (CloseableHttpResponse response = httpClient.execute(httpGet)) {
                int status = response.getStatusLine().getStatusCode();
                if (status >= 200 && status < 300) {
                    HttpEntity entity = response.getEntity();
                    if (entity == null) {
                        return "";
                    }
                    ContentType contentType = ContentType.getOrDefault(entity);
                    Charset charset = contentType.getCharset();
                    if (charset == null) {
                        charset = StandardCharsets.UTF_8;
                    }
                    // EntityUtils will automatically handle decompression when using the default client
                    return EntityUtils.toString(entity, charset);
                } else {
                    // Ensure the entity is fully consumed before throwing
                    EntityUtils.consumeQuietly(response.getEntity());
                    throw new HttpResponseException(status, response.getStatusLine().getReasonPhrase());
                }
            }
        }
    }

    private static URI toHttpOrHttpsUri(String url) {
        try {
            URL parsed = new URL(url);
            String protocol = parsed.getProtocol();
            if (!"http".equalsIgnoreCase(protocol) && !"https".equalsIgnoreCase(protocol)) {
                throw new IllegalArgumentException("Unsupported URL scheme: " + protocol + " (only http/https allowed).");
            }
            return parsed.toURI();
        } catch (MalformedURLException | URISyntaxException e) {
            throw new IllegalArgumentException("Invalid URL: " + url, e);
        }
    }
}

