        DnsResolver safeResolver = new SystemDefaultDnsResolver() {
            @Override
            public InetAddress[] resolve(String host) throws java.net.UnknownHostException {
                InetAddress[] addrs = super.resolve(host);
                for (InetAddress addr : addrs) {
                    if (isPrivateOrReserved(addr)) {
                        throw new java.net.UnknownHostException("Blocked resolution to non-public address: " + addr.getHostAddress());
