                    HttpEntity entity = response.getEntity();
                    if (entity == null) {
                        return "";
                    }

                    long declaredLength = entity.getContentLength();
                    if (declaredLength > MAX_CONTENT_SIZE_BYTES) {
                        EntityUtils.consumeQuietly(entity);
                        throw new IOException("Response too large: " + declaredLength + " bytes");
                    }

                    byte[] data = readWithLimit(entity.getContent(), MAX_CONTENT_SIZE_BYTES);
                    Charset charset = extractCharset(entity);
                    return new String(data, charset);
                }

                // Other status codes treated as errors
                EntityUtils.consumeQuietly(response.getEntity());
                throw new IOException("HTTP request failed with status " + status + " for " + currentUri.toASCIIString());
            }
        }

        throw new IOException("Too many redirects (>" + MAX_REDIRECTS + ")");
    }

    private static boolean isRedirect(int status) {
        return status == 301 || status == 302 || status == 303 || status == 307 || status == 308;
    }

    private static String getRedirectLocation(CloseableHttpResponse response) {
        if (response.getFirstHeader(HttpHeaders.LOCATION) == null) {
            return null;
        }
        return response.getFirstHeader(HttpHeaders.LOCATION).getValue();
    }

    private static URI resolveAndRevalidateRedirect(URI base, String location) throws IOException {
        URI target;
        try {
            URI loc = new URI(location);
            target = loc.isAbsolute() ? loc : base.resolve(loc);
        } catch (URISyntaxException e) {
            throw new IOException("Invalid redirect URI: " + location, e);
