        if (uri.getScheme() == null) {
            throw new IOException("URL must include scheme (http or https)");
        }
        String scheme = uri.getScheme().toLowerCase();
        if (!"http".equals(scheme) && !"https".equals(scheme)) {
            throw new IOException("Only http and https schemes are allowed");
        }
        if (uri.getUserInfo() != null) {
            throw new IOException("User info in URL is not allowed");
        }
        if (uri.getHost() == null || uri.getHost().trim().isEmpty()) {
            throw new IOException("URL must include a valid host");
        }

        // Drop fragment to avoid leaking client-side fragments to server
        try {
            uri = new URI(
                    uri.getScheme(),
                    uri.getUserInfo(),
                    uri.getHost(),
                    uri.getPort(),
                    uri.getPath(),
                    uri.getQuery(),
                    null
            );
        } catch (URISyntaxException e) {
            throw new IOException("Failed to normalize URL", e);
        }

        // Additional fast-fail DNS resolution check using the same logic as the client resolver
        // to provide early feedback before attempting the request.
        try {
            InetAddress[] addrs = InetAddress.getAllByName(uri.getHost());
            for (InetAddress addr : addrs) {
                if (isPrivateOrReserved(addr)) {
                    throw new IOException("Blocked host resolves to non-public address: " + addr.getHostAddress());
                }
            }
        } catch (IOException ex) {
            // Re-throw as-is
            throw ex;
        } catch (Exception ex) {
            // DNS resolution issues
            throw new IOException("Failed to resolve host: " + uri.getHost(), ex);
        }

        return uri;
    }

    private static Charset extractCharset(HttpEntity entity) {
        try {
            ContentType ct = ContentType.get(entity);
            Charset cs = (ct != null) ? ct.getCharset() : null;
            return cs != null ? cs : StandardCharsets.UTF_8;
        } catch (Exception e) {
            return StandardCharsets.UTF_8;
        }
    }

    private static byte[] readWithLimit(InputStream in, int maxBytes) throws IOException {
        try (InputStream is = in; ByteArrayOutputStream out = new ByteArrayOutputStream(Math.min(maxBytes, 8192))) {
            byte[] buffer = new byte[8192];
            int total = 0;
            int read;
            while ((read = is.read(buffer)) != -1) {
                if (total + read > maxBytes) {
                    int allowed = maxBytes - total;
                    if (allowed > 0) {
                        out.write(buffer, 0, allowed);
                        total += allowed;
                    }
                    throw new IOException("Response too large (exceeds " + maxBytes + " bytes)");
                }
                out.write(buffer, 0, read);
                total += read;
            }
            return out.toByteArray();
        }
    }

    private static boolean isPrivateOrReserved(InetAddress addr) {
        // Common cases first
        if (addr.isAnyLocalAddress() || addr.isLoopbackAddress()
                || addr.isLinkLocalAddress() || addr.isSiteLocalAddress()
                || addr.isMulticastAddress()) {
            return true;
        }

        byte[] a = addr.getAddress();

        if (addr instanceof Inet4Address) {
            int b0 = a[0] & 0xFF;
            int b1 = a[1] & 0xFF;
            int b2 = a[2] & 0xFF;

            // 100.64.0.0/10 (CGNAT)
            if (b0 == 100 && (b1 & 0xC0) == 64) return true;

            // 192.0.0.0/24
            if (b0 == 192 && b1 == 0 && b2 == 0) return true;

            // 198.18.0.0/15 (benchmarking)
            if (b0 == 198 && (b1 == 18 || b1 == 19)) return true;

            // 192.0.2.0/24, 198.51.100.0/24, 203.0.113.0/24 (TEST-NETs)
            if ((b0 == 192 && b1 == 0 && b2 == 2)
                    || (b0 == 198 && b1 == 51 && b2 == 100)
                    || (b0 == 203 && b1 == 0 && b2 == 113)) return true;

            // 0.0.0.0/8
            if (b0 == 0) return true;

            // 240.0.0.0/4 (includes 255.255.255.255)
            if (b0 >= 240) return true;
        } else if (addr instanceof Inet6Address) {
            int first = a[0] & 0xFF;

            // Unique local addresses fc00::/7
            if ((first & 0xFE) == 0xFC) return true;

            // Other cases like loopback/link-local/multicast handled above
        }

        return false;
    }

    @Override
    public void close() throws IOException {
        httpClient.close();
    }
}

