import java.net.InetAddress;
import java.net.URI;
import java.net.URISyntaxException;
import java.net.UnknownHostException;
import java.nio.charset.Charset;
import java.nio.charset.StandardCharsets;
import java.util.Locale;

/**
 * URL内容获取服务（修复了SSRF与资源消耗等安全问题）
 */
public class UrlService {

    // 连接超时时间（毫秒）
    private static final int CONNECT_TIMEOUT = 10000;
    // 读取超时时间（毫秒）
    private static final int SOCKET_TIMEOUT = 30000;
    // 连接租借超时时间（毫秒）
    private static final int CONNECTION_REQUEST_TIMEOUT = 10000;
    // 最大允许重定向次数
    private static final int MAX_REDIRECTS = 5;
    // 最大读取内容大小（字节），防止内存被大响应耗尽（默认2MB）
    private static final int MAX_CONTENT_SIZE = 2 * 1024 * 1024;

    /**
     * 获取指定URL的内容
     *
     * 安全措施：
     * - 仅允许 http/https 协议
     * - 禁止带有用户凭据的URL（userinfo）
     * - 限制端口为常见HTTP端口（80/443/8080/8443）
     * - 通过自定义DnsResolver屏蔽到内网、环回、链路本地、组播、ULA等地址的解析（防SSRF/DNS重绑定）
     * - 对重定向目标进行协议、端口与基本格式校验
     * - 限制响应体最大读取大小（防止内存耗尽/压缩炸弹）
     * - 合理的超时设置
     *
     * @param userUrl 用户提供的URL字符串
     * @return 响应体内容字符串，如果发生错误或校验失败则返回null
     */
    public String fetchUrlContent(String userUrl) {
        if (userUrl == null || userUrl.trim().isEmpty()) {
            return null;
        }

        final URI uri;
        try {
            uri = new URI(userUrl.trim());
        } catch (URISyntaxException e) {
            return null;
        }

        // 方案校验
        String scheme = uri.getScheme();
        if (scheme == null) {
            return null;
        }
        scheme = scheme.toLowerCase(Locale.ROOT);
        if (!("http".equals(scheme) || "https".equals(scheme))) {
            return null;
        }

        // 主机与userinfo校验
        String host = uri.getHost();
        if (host == null || host.trim().isEmpty()) {
            return null;
        }
        if (uri.getUserInfo() != null) {
            return null;
        }

        // 端口校验
        int effectivePort = effectivePort(uri);
        if (!isPortAllowed(effectivePort)) {
            return null;
        }

        // 自定义DNS解析器（过滤内网、环回、链路本地、ULA等地址）
        SafeDnsResolver dnsResolver = new SafeDnsResolver();

        // 预先解析一次（快速失败）
        try {
            InetAddress[] addrs = dnsResolver.resolve(host);
            if (addrs == null || addrs.length == 0) {
                return null;
            }
        } catch (UnknownHostException e) {
            return null;
        }

        RequestConfig requestConfig = RequestConfig.custom()
                .setConnectTimeout(CONNECT_TIMEOUT)
                .setSocketTimeout(SOCKET_TIMEOUT)
                .setConnectionRequestTimeout(CONNECTION_REQUEST_TIMEOUT)
                .setMaxRedirects(MAX_REDIRECTS)
                .build();

        // 自定义重定向策略：校验重定向目标协议、端口、格式
        ValidatingRedirectStrategy redirectStrategy = new ValidatingRedirectStrategy();

        try (CloseableHttpClient httpClient = HttpClientBuilder.create()
                .setDefaultRequestConfig(requestConfig)
                .setRedirectStrategy(redirectStrategy)
                .setDnsResolver(dnsResolver)
                .disableCookieManagement()
                .build()) {

            HttpGet httpGet = new HttpGet(uri);
            httpGet.setConfig(requestConfig);
            // 适度设置头
            httpGet.setHeader("User-Agent", "UrlService/1.0 (+https://example.com)");
            httpGet.setHeader("Accept", "*/*");

            try (CloseableHttpResponse response = httpClient.execute(httpGet)) {
                int statusCode = response.getStatusLine().getStatusCode();
                if (statusCode != HttpStatus.SC_OK) {
                    return null;
                }

                HttpEntity entity = response.getEntity();
                if (entity == null) {
                    return null;
                }

                long contentLength = entity.getContentLength();
                if (contentLength > MAX_CONTENT_SIZE) {
                    return null;
                }

                try (InputStream in = entity.getContent()) {
                    byte[] data = readWithLimit(in, MAX_CONTENT_SIZE);
                    if (data == null) {
                        return null;
                    }
                    Charset charset = ContentType.getOrDefault(entity).getCharset();
                    if (charset == null) {
                        charset = StandardCharsets.UTF_8;
                    }
                    return new String(data, charset);
                }
            }
        } catch (IOException e) {
            return null;
        } catch (Exception e) {
            return null;
        }
    }

    // 读取输入流，限制最大字节数，超出则返回null
    private static byte[] readWithLimit(InputStream in, int maxBytes) throws IOException {
        byte[] buffer = new byte[8192];
        ByteArrayOutputStream baos = new ByteArrayOutputStream(Math.min(maxBytes, 65536));
        int total = 0;
        int read;
        while ((read = in.read(buffer)) != -1) {
            total += read;
            if (total > maxBytes) {
                return null;
            }
            baos.write(buffer, 0, read);
        }
        return baos.toByteArray();
    }

    private static int effectivePort(URI uri) {
        int port = uri.getPort();
        if (port != -1) return port;
        String s = uri.getScheme();
        if ("https".equalsIgnoreCase(s)) return 443;
        return 80;
    }

    private static boolean isPortAllowed(int port) {
        // 仅允许常见HTTP端口，降低访问敏感服务的风险
        return port == 80 || port == 443 || port == 8080 || port == 8443;
    }

    // 自定义重定向策略：限制协议、端口、基本格式
    private static class ValidatingRedirectStrategy extends DefaultRedirectStrategy {
        @Override
        public URI getLocationURI(org.apache.http.HttpRequest request, HttpResponse response, HttpContext context)
                throws ProtocolException {
            URI location = super.getLocationURI(request, response, context);
            if (location == null) {
                throw new ProtocolException("Redirect URI is null");
            }
            String scheme = location.getScheme();
            if (scheme == null) {
                throw new ProtocolException("Redirect URI missing scheme");
            }
            scheme = scheme.toLowerCase(Locale.ROOT);
            if (!("http".equals(scheme) || "https".equals(scheme))) {
                throw new ProtocolException("Blocked redirect scheme: " + scheme);
            }
            if (location.getUserInfo() != null) {
                throw new ProtocolException("Blocked redirect with userinfo");
            }
            String host = location.getHost();
            if (host == null || host.trim().isEmpty()) {
                throw new ProtocolException("Redirect URI missing host");
            }
            int port = effectivePort(location);
            if (!isPortAllowed(port)) {
                throw new ProtocolException("Blocked redirect port: " + port);
            }
            return location;
        }
    }

    // 自定义DNS解析器：过滤内网/环回/链路本地/ULA/保留网段
    private static class SafeDnsResolver implements DnsResolver {
        @Override
        public InetAddress[] resolve(String host) throws UnknownHostException {
            InetAddress[] addresses = InetAddress.getAllByName(host);
            // 过滤不安全地址
            java.util.List<InetAddress> safe = new java.util.ArrayList<>();
            for (InetAddress addr : addresses) {
                if (isAddressAllowed(addr)) {
                    safe.add(addr);
                }
            }
            if (safe.isEmpty()) {
                throw new UnknownHostException("All resolved addresses are blocked by SSRF protection");
            }
            return safe.toArray(new InetAddress[0]);
        }

        private static boolean isAddressAllowed(InetAddress addr) {
            // 通用快速拒绝
            if (addr.isAnyLocalAddress()) return false;      // 0.0.0.0 / ::
            if (addr.isLoopbackAddress()) return false;      // 127.0.0.0/8 / ::1
            if (addr.isLinkLocalAddress()) return false;     // 169.254.0.0/16 / fe80::/10
            if (addr.isSiteLocalAddress()) return false;     // RFC1918 / (部分IPv6 site-local)

            if (addr.isMulticastAddress()) return false;     // 224.0.0.0/4 / ff00::/8

            if (addr instanceof Inet4Address) {
                return !isPrivateOrReservedIPv4((Inet4Address) addr);
            } else if (addr instanceof Inet6Address) {
                return !isPrivateOrReservedIPv6((Inet6Address) addr);
            } else {
                // 未知类型，保守处理
                return false;
            }
        }

        private static boolean isPrivateOrReservedIPv4(Inet4Address a) {
            byte[] b = a.getAddress();
            int b0 = b[0] & 0xFF;
            int b1 = b[1] & 0xFF;
            int b2 = b[2] & 0xFF;
            // 10.0.0.0/8
            if (b0 == 10) return true;
            // 172.16.0.0/12
            if (b0 == 172 && (b1 >= 16 && b1 <= 31)) return true;
            // 192.168.0.0/16
            if (b0 == 192 && b1 == 168) return true;
            // 127.0.0.0/8
            if (b0 == 127) return true;
            // 169.254.0.0/16
            if (b0 == 169 && b1 == 254) return true;
            // 100.64.0.0/10 (CGNAT)
            if (b0 == 100 && (b1 >= 64 && b1 <= 127)) return true;
            // 192.0.0.0/24
            if (b0 == 192 && b1 == 0 && b2 == 0) return true;
            // 198.18.0.0/15 (benchmark)
            if (b0 == 198 && (b1 == 18 || b1 == 19)) return true;
            // 0.0.0.0/8
            if (b0 == 0) return true;
            // 广播 255.255.255.255（isMulticast不涵盖）
            if (b0 == 255 && (b[1] & 0xFF) == 255 && (b[2] & 0xFF) == 255 && (b[3] & 0xFF) == 255) return true;
            return false;
        }

        private static boolean isPrivateOrReservedIPv6(Inet6Address a) {
            byte[] b = a.getAddress();
            // Unique Local Address fc00::/7 (fc.. or fd..)
            int first = b[0] & 0xFF;
            if ((first & 0xFE) == 0xFC) {
                return true;
            }
            // 其他保留网段可按需扩展，这里基本校验已由 isAnyLocal/isLoopback/isLinkLocal/isMulticast 覆盖
            return false;
        }
    }
}

