            if (b0 >= 224 && b0 <= 239) return true;
            // 240.0.0.0/4 保留/广播
            if (b0 >= 240) return true;
        } else if (address instanceof Inet6Address) {
            byte[] b = address.getAddress();
            int b0 = b[0] & 0xFF;
            int b1 = b[1] & 0xFF;

            // ::/128 未指定
            boolean allZero = true;
            for (byte value : b) {
