     * 安全DNS解析器：仅允许解析到公共可路由地址
     */
    private static class SafeDnsResolver implements DnsResolver {
        @Override
        public InetAddress[] resolve(String host) throws UnknownHostException {
            if (host == null || host.trim().isEmpty()) {
                throw new UnknownHostException("Empty host");
            }

            // 对非IP字面量的国际化域名进行ASCII转换以避免解析异常
            String normalizedHost = host;
            if (!isIpLiteral(host)) {
                normalizedHost = IDN.toASCII(host, IDN.USE_STD3_ASCII_RULES);
            }

            InetAddress[] resolved = InetAddress.getAllByName(normalizedHost);
            // 过滤受限地址
            java.util.List<InetAddress> allowed = new java.util.ArrayList<>(resolved.length);
            for (InetAddress addr : resolved) {
                if (!isProhibitedAddress(addr)) {
                    allowed.add(addr);
                }
            }
            if (allowed.isEmpty()) {
                throw new UnknownHostException("Host resolves to prohibited addresses");
            }
            return allowed.toArray(new InetAddress[0]);
        }
    }
}

