        }

        URI uri = buildAndValidateUri(trimmed);
        if (uri == null) {
            return null;
        }

        HttpGet httpGet = new HttpGet(uri);
        httpGet.setConfig(DEFAULT_REQUEST_CONFIG);
        // 常见头部
        httpGet.setHeader("Accept", "text/html,application/xhtml+xml,application/xml,application/json;q=0.9,*/*;q=0.8");
        httpGet.setHeader("Accept-Encoding", "gzip, deflate");
        httpGet.setHeader("Accept-Language", "en-US,en;q=0.9,zh-CN;q=0.8,zh;q=0.7");

        try (CloseableHttpResponse response = HTTP_CLIENT.execute(httpGet)) {
            int statusCode = response.getStatusLine().getStatusCode();
            if (statusCode < HttpStatus.SC_OK || statusCode >= HttpStatus.SC_MULTIPLE_CHOICES) {
                // 非2xx状态码返回null
                return null;
            }

            HttpEntity entity = response.getEntity();
            if (entity == null) {
                return null;
            }

            // 如果声明的Content-Length超过上限，直接放弃
            long declaredLength = entity.getContentLength();
            if (declaredLength > MAX_CONTENT_LENGTH) {
                return null;
            }

            // 根据Content-Type推断字符集
            Charset charset = extractCharset(entity);
            String content = readEntityToString(entity, MAX_CONTENT_LENGTH, charset);
            return content;
        } catch (IOException | RuntimeException e) {
            // 可根据需要接入日志系统记录异常
            return null;
        }
    }

    private static Charset extractCharset(HttpEntity entity) {
        try {
            ContentType ct = ContentType.get(entity);
            if (ct != null && ct.getCharset() != null) {
                return ct.getCharset();
            }
        } catch (Exception ignored) {
