        return DEFAULT_CHARSET;
    }

    private static String readEntityToString(HttpEntity entity, int maxBytes, Charset charset) throws IOException {
        try (InputStream in = entity.getContent(); ByteArrayOutputStream out = new ByteArrayOutputStream()) {
            byte[] buffer = new byte[8192];
            int read;
            int total = 0;
            while ((read = in.read(buffer)) != -1) {
                total += read;
                if (total > maxBytes) {
                    // 超过限制，返回null（也可抛出异常交由上层处理）
                    return null;
                }
                out.write(buffer, 0, read);
            }
            return new String(out.toByteArray(), charset);
        }
    }

    private static URI buildAndValidateUri(String url) {
        // 优先尝试直接解析
        try {
            URI uri = new URI(url);
            if (!isHttpScheme(uri)) {
                return null;
            }
            return uri;
        } catch (URISyntaxException ignored) {
        }

        // 回退使用URIBuilder尝试修正常见的URL不规范情况（如空格）
        try {
            URI uri = new URIBuilder(url).build();
            if (!isHttpScheme(uri)) {
                return null;
            }
            return uri;
        } catch (URISyntaxException ignored) {
            return null;
        }
    }

    private static boolean isHttpScheme(URI uri) {
        String scheme = uri.getScheme();
        if (scheme == null) {
            return false;
        }
        String s = scheme.toLowerCase();
        return "http".equals(s) || "https".equals(s);
    }
}

