        if (ipv4InRange(ip, ipv4(127, 0, 0, 0), 8)) return false;        // 127.0.0.0/8
        if (ipv4InRange(ip, ipv4(169, 254, 0, 0), 16)) return false;     // 169.254.0.0/16
        if (ipv4InRange(ip, ipv4(0, 0, 0, 0), 8)) return false;          // 0.0.0.0/8
